const env = typeof $env !== 'undefined' ? $env : {};
const supabaseUrl = (env.SUPABASE_URL || process.env.SUPABASE_URL || '').replace(/\/$/, '');
const serviceRoleKey = env.SUPABASE_SERVICE_ROLE_KEY || process.env.SUPABASE_SERVICE_ROLE_KEY || '';

if (!supabaseUrl || !serviceRoleKey) {
  throw new Error('Missing SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY in n8n environment.');
}

const restHeaders = {
  apikey: serviceRoleKey,
  Authorization: `Bearer ${serviceRoleKey}`,
  'Content-Type': 'application/json',
};

async function httpRequest(options) {
  return this.helpers.httpRequest({ json: true, ...options });
}

async function supabaseGet(path) {
  return httpRequest.call(this, { method: 'GET', url: `${supabaseUrl}/rest/v1/${path}`, headers: restHeaders });
}

async function supabasePost(path, body) {
  return httpRequest.call(this, {
    method: 'POST',
    url: `${supabaseUrl}/rest/v1/${path}`,
    headers: { ...restHeaders, Prefer: 'return=representation' },
    body,
  });
}

function enc(value) {
  return encodeURIComponent(String(value));
}

function utcDate(date = new Date()) {
  return date.toISOString().slice(0, 10);
}

function timeToMinutes(value) {
  const [hours = '0', minutes = '0'] = String(value || '00:00').split(':');
  return Number(hours) * 60 + Number(minutes);
}

function compactIds(rows, key = 'id', max = 20) {
  return (rows || []).map((row) => row[key]).filter(Boolean).slice(0, max);
}

const now = new Date();
const digestDate = utcDate(now);
const windowStart = new Date(now.getTime() - 24 * 60 * 60 * 1000).toISOString();
const windowEnd = now.toISOString();
const href = `/admin/automation/admin-ops-digest?date=${digestDate}`;
const runStartedAt = windowEnd;

const admins = await supabaseGet('user_profiles?select=id,is_admin&is_admin=eq.true&limit=1000');
const newUsers = await supabaseGet(`user_profiles?select=id,created_at&created_at=gte.${enc(windowStart)}&created_at=lte.${enc(windowEnd)}&limit=2000`);
const pendingCoaches = await supabaseGet('coach_profiles?select=id,status&status=eq.pending&limit=2000');
const bookings = await supabaseGet(`bookings?select=id,status,scheduled_at&scheduled_at=gte.${enc(windowStart)}&scheduled_at=lte.${enc(windowEnd)}&limit=3000`);
const packPurchases = await supabaseGet(`purchased_packs?select=id,status,purchased_at&created_at=gte.${enc(windowStart)}&created_at=lte.${enc(windowEnd)}&limit=3000`);

const completedBookings = (bookings || []).filter((booking) => booking.status === 'completed');
const cancelledBookings = (bookings || []).filter((booking) => booking.status === 'cancelled');
const noShowBookings = (bookings || []).filter((booking) => booking.status === 'no_show');
const automationFailures = 0;
const message = [
  `New users: ${newUsers.length}`,
  `Pending coaches: ${pendingCoaches.length}`,
  `Completed bookings: ${completedBookings.length}`,
  `Cancelled bookings: ${cancelledBookings.length}`,
  `No-shows: ${noShowBookings.length}`,
  `Pack purchases: ${packPurchases.length}`,
  `Tracked automation failures: ${automationFailures}`,
].join(' | ');

const results = [];
const stats = {
  run_started_at: runStartedAt,
  window_start: windowStart,
  window_end: windowEnd,
  digest_date: digestDate,
  admins_found: (admins || []).length,
  new_users_count: newUsers.length,
  pending_coaches_count: pendingCoaches.length,
  completed_bookings_count: completedBookings.length,
  cancelled_bookings_count: cancelledBookings.length,
  no_show_bookings_count: noShowBookings.length,
  pack_purchases_count: packPurchases.length,
  automation_failures_count: automationFailures,
  created_count: 0,
  skipped_existing_digest_count: 0,
  error_count: 0,
};

for (const admin of admins || []) {
  try {
    const existing = await supabaseGet(`admin_notifications?select=id&admin_user_id=eq.${admin.id}&title=eq.${enc('Daily ops digest')}&href=eq.${enc(href)}&limit=1`);
    if (existing[0]?.id) {
      stats.skipped_existing_digest_count += 1;
      results.push({ admin_user_id: admin.id, status: 'skipped_existing_digest', admin_notification_id: existing[0].id });
      continue;
    }

    const inserted = await supabasePost('admin_notifications', {
      admin_user_id: admin.id,
      type: 'info',
      title: 'Daily ops digest',
      message,
      href,
    });

    const notification = inserted[0];
    if (!notification?.id) throw new Error('Supabase did not return inserted admin notification id.');
    stats.created_count += 1;
    results.push({ admin_user_id: admin.id, status: 'created', admin_notification_id: notification.id });
  } catch (error) {
    stats.error_count += 1;
    results.push({ admin_user_id: admin.id, status: 'error', error: error instanceof Error ? error.message : String(error) });
  }
}

return [
  { json: { type: 'summary', status: stats.error_count > 0 ? 'completed_with_errors' : 'completed', finished_at: new Date().toISOString(), ...stats } },
  ...results.map((result) => ({ json: { type: 'admin_result', ...result } })),
];
